const results = [];
const BOT_PHONE = $vars.BOT_PHONE || '';

for (const item of $input.all()) {
  const payload = item.json?.body?.payload;
  if (!payload) continue;

  const isMessage = item.json.body.event === 'message';
  const isNotMe = payload.fromMe === false;
  const hasTextBody = payload.body && payload.body.trim() !== '';
  if (!isMessage || !isNotMe || !hasTextBody) continue;

  const isGroup = (payload.from || '').endsWith('@g.us');

  // Detectar si el bot fue mencionado en el grupo
  if (isGroup) {
    const mentioned = payload.mentionedJidList || payload._data?.mentionedJidList || [];
    const botMentioned = (BOT_PHONE && mentioned.some(j => j.includes(BOT_PHONE)))
      || mentioned.length > 0; // si hay cualquier menciГіn asumimos que puede ser al bot
    if (!botMentioned) continue; // ignorar mensajes de grupo sin menciГіn

    results.push({
      json: {
        phone: payload.from,
        message: payload.body,
        fromMe: payload.fromMe,
        messageId: payload.id,
        isGroupMention: true
      }
    });
    continue;
  }

  // Mensajes privados normales
  let phone = payload.from;
  if (phone && phone.endsWith('@lid')) {
    const alt = payload._data?.key?.remoteJidAlt;
    if (alt) phone = alt;
  }

  results.push({
    json: {
      phone: phone,
      message: payload.body,
      fromMe: payload.fromMe,
      messageId: payload.id
    }
  });
}
return results;

