const lead = $input.first().json.lead;

const phoneClean = (lead.phone || '')
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '');
const phoneDisplay = phoneClean ? `+${phoneClean}` : 'No proporcionado';

const tz = 'America/Santo_Domingo';

function toLocalDate(date) {
  return new Date(date.toLocaleString('en-US', { timeZone: tz }));
}

// Si el usuario ya eligiГі un slot desde el chatbot, usarlo directamente
let slot;
if (lead.slotChosen) {
  slot = new Date(lead.slotChosen);
} else {
  // Fallback: calcular el prГіximo slot hГЎbil automГЎticamente (leads de web)
  slot = new Date();
  slot.setMinutes(0, 0, 0);
  slot.setHours(slot.getHours() + 1);

  for (let i = 0; i < 200; i++) {
    const local = toLocalDate(slot);
    const day = local.getDay();
    const hour = local.getHours();
    if (day >= 1 && day <= 5 && hour >= 9 && hour < 17) break;
    slot.setHours(slot.getHours() + 1);
    const localCheck = toLocalDate(slot);
    if (localCheck.getHours() >= 17) {
      slot.setDate(slot.getDate() + 1);
      slot.setHours(9, 0, 0, 0);
    }
    if (toLocalDate(slot).getDay() === 6) {
      slot.setDate(slot.getDate() + 2);
      slot.setHours(9, 0, 0, 0);
    }
    if (toLocalDate(slot).getDay() === 0) {
      slot.setDate(slot.getDate() + 1);
      slot.setHours(9, 0, 0, 0);
    }
  }
}

const slotEnd = new Date(slot);
slotEnd.setHours(slotEnd.getHours() + 1);

function formatCalDAV(date) {
  return date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
}

const dias = ['Domingo','Lunes','Martes','MiГ©rcoles','Jueves','Viernes','SГЎbado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const localSlot = toLocalDate(slot);
const fechaTexto = `${dias[localSlot.getDay()]} ${localSlot.getDate()} de ${meses[localSlot.getMonth()]} a las ${localSlot.getHours()}:00`;

const uid = `synset-${Date.now()}@synsetsolutions.com`;

const icsContent = `BEGIN:VCALENDAR\r\nVERSION:2.0\r\nPRODID:-//Synset Solutions//Chatbot//ES\r\nBEGIN:VEVENT\r\nUID:${uid}\r\nDTSTAMP:${formatCalDAV(new Date())}\r\nDTSTART:${formatCalDAV(slot)}\r\nDTEND:${formatCalDAV(slotEnd)}\r\nSUMMARY:AuditorГ­a Gratuita - ${lead.nombre}\r\nDESCRIPTION:Lead desde ${lead.source === 'web' ? 'Web' : 'WhatsApp'}\\nTelГ©fono: ${phoneDisplay}\\nEmail: ${lead.email}\\nDesafГ­o: ${lead.desafio}\r\nORGANIZER:mailto:contact@synsetsolutions.com\r\nATTENDEE:mailto:${lead.email}\r\nEND:VEVENT\r\nEND:VCALENDAR`;

return [{
  json: {
    lead,
    uid,
    icsContent,
    fechaTexto,
    phoneDisplay,
    calendarUrl: `https://cloud.synsetsolutions.com/remote.php/dav/calendars/adminsynset/personal/${uid}.ics`
  }
}];

